1	/**
2	 * IDE Skill Installer — Verbatim skill directory installation
3	 *
4	 * Replaces the legacy command-file generation approach with the BMAD standard:
5	 * skill directories (containing SKILL.md + supporting files) are copied directly
6	 * to each IDE's skills/ directory. IDEs read SKILL.md natively.
7	 *
8	 * Supports 23+ IDEs via platform-codes.yaml (config-driven, no IDE-specific code).
9	 */
10	
11	const path = require('node:path');
12	const fs = require('fs-extra');
13	const yaml = require('js-yaml');
14	
15	const PLATFORM_CODES_PATH = path.join(__dirname, 'platform-codes.yaml');
16	
17	// OS/editor artifacts to filter during copy
18	const ARTIFACT_FILTER = new Set(['.DS_Store', 'Thumbs.db', 'desktop.ini', '._.DS_Store']);
19	
20	/**
21	 * Load platform configuration from platform-codes.yaml.
22	 * Returns { platforms: { 'claude-code': { name, preferred, installer: { target_dir, legacy_targets } }, ... } }
23	 */
24	function loadPlatforms() {
25	  const content = fs.readFileSync(PLATFORM_CODES_PATH, 'utf8');
26	  return yaml.load(content);
27	}
28	
29	/**
30	 * Get available platforms for UI display.
31	 * Returns array of { value: 'claude-code', label: 'Claude Code', preferred: true }
32	 */
33	function getAvailablePlatforms() {
34	  const config = loadPlatforms();
35	  return Object.entries(config.platforms)
36	    .filter(([, p]) => !p.suspended)
37	    .map(([code, p]) => ({
38	      value: code,
39	      label: p.name,
40	      preferred: p.preferred || false,
41	    }))
42	    .sort((a, b) => {
43	      // Preferred first, then alphabetical
44	      if (a.preferred !== b.preferred) return b.preferred ? 1 : -1;
45	      return a.label.localeCompare(b.label);
46	    });
47	}
48	
49	/**
50	 * Get IDE auto-detection markers.
51	 * Returns { 'claude-code': ['.claude'], 'cursor': ['.cursor'], ... }
52	 *
53	 * Uses explicit detection_marker from platform config when available,
54	 * otherwise derives from the top-level directory of target_dir.
55	 * The derived marker only works when the IDE's config directory exists
56	 * independently of the installer (e.g. .claude/ exists before SKF install).
57	 */
58	function getDetectionMarkers() {
59	  const config = loadPlatforms();
60	  const markers = {};
61	  for (const [code, p] of Object.entries(config.platforms)) {
62	    if (p.suspended) continue;
63	    const targetDir = p.installer?.target_dir;
64	    if (!targetDir) continue;
65	    if (p.installer.detection_marker) {
66	      markers[code] = [p.installer.detection_marker];
67	    } else {
68	      // Derive from target_dir — works when top-level dir is the IDE's own config dir
69	      const topDir = '.' + targetDir.split('/')[0].replace(/^\./, '');
70	      markers[code] = [topDir];
71	    }
72	  }
73	  return markers;
74	}
75	
76	/**
77	 * Install skill directories to all selected IDEs.
78	 *
79	 * @param {string} projectDir - Project root directory
80	 * @param {string} skfDir - Path to installed SKF module (e.g., {projectDir}/_bmad/skf)
81	 * @param {string[]} ideCodes - Array of IDE codes (e.g., ['claude-code', 'cursor'])
82	 * @returns {{ installed: number, ides: string[], directories: string[] }}
83	 */
84	async function installSkillsToIdes(projectDir, skfDir, ideCodes) {
85	  if (!ideCodes || ideCodes.length === 0) return { installed: 0, ides: [], directories: [] };
86	
87	  const config = loadPlatforms();
88	  let totalInstalled = 0;
89	  const processedIdes = [];
90	  const allDirectories = [];
91	
92	  // Copy filter: skip OS artifacts
93	  const copyFilter = (src) => !ARTIFACT_FILTER.has(path.basename(src));
94	
95	  for (const ideCode of ideCodes) {
96	    const platform = config.platforms[ideCode];
97	    if (!platform || !platform.installer?.target_dir) continue;
98	
99	    const targetDir = path.join(projectDir, platform.installer.target_dir);
100	
101	    // Clean legacy targets first (old command files from previous SKF installs)
102	    await cleanLegacyTargets(projectDir, platform);
103	
104	    // Clean existing SKF skills from this IDE (for update/reinstall)
105	    await cleanSkfSkills(targetDir);
106	
107	    // Ensure target directory exists
108	    await fs.ensureDir(targetDir);
109	
110	    // Copy all skf-* skill directories from the installed module
111	    if (await fs.pathExists(skfDir)) {
112	      const entries = await fs.readdir(skfDir, { withFileTypes: true });
113	      for (const entry of entries) {
114	        if (!entry.isDirectory()) continue;
115	
116	        // Copy skill directories (skf-*) and supporting resources (knowledge/, shared/)
117	        if (entry.name.startsWith('skf-') || entry.name === 'knowledge' || entry.name === 'shared') {
118	          const src = path.join(skfDir, entry.name);
119	          const dest = path.join(targetDir, entry.name);
120	          await fs.copy(src, dest, { filter: copyFilter });
121	          totalInstalled++;
122	        }
123	      }
124	    }
125	
126	    allDirectories.push(platform.installer.target_dir);
127	    processedIdes.push(ideCode);
128	  }
129	
130	  return { installed: totalInstalled, ides: processedIdes, directories: allDirectories };
131	}
132	
133	/**
134	 * Remove legacy command files from old IDE target directories.
135	 * Handles migration from command-file approach to skill-directory approach.
136	 */
137	async function cleanLegacyTargets(projectDir, platform) {
138	  const legacyTargets = platform.installer?.legacy_targets || [];
139	
140	  for (const legacyDir of legacyTargets) {
141	    const fullPath = path.join(projectDir, legacyDir);
142	    if (!(await fs.pathExists(fullPath))) continue;
143	
144	    try {
145	      const files = await fs.readdir(fullPath);
146	      for (const file of files) {
147	        // Remove SKF-specific command files from legacy directories
148	        if (file.startsWith('bmad-skf-') || file.startsWith('bmad-agent-skf-')) {
149	          await fs.remove(path.join(fullPath, file));
150	        }
151	      }
152	
153	      // Remove empty directories
154	      const remaining = await fs.readdir(fullPath);
155	      if (remaining.length === 0) {
156	        await fs.remove(fullPath);
157	        // Also try to remove empty parent
158	        const parentDir = path.dirname(fullPath);
159	        try {
160	          const parentRemaining = await fs.readdir(parentDir);
161	          if (parentRemaining.length === 0) await fs.remove(parentDir);
162	        } catch {
163	          /* ignore */
164	        }
165	      }
166	    } catch {
167	      /* non-critical, continue */
168	    }
169	  }
170	}
171	
172	/**
173	 * Remove existing SKF skill directories from an IDE target.
174	 * Called before reinstalling to ensure clean state.
175	 */
176	async function cleanSkfSkills(targetDir) {
177	  if (!(await fs.pathExists(targetDir))) return;
178	
179	  try {
180	    const entries = await fs.readdir(targetDir);
181	    for (const entry of entries) {
182	      // Only remove SKF-owned directories (skf-*, knowledge, shared)
183	      if (entry.startsWith('skf-') || entry === 'knowledge' || entry === 'shared') {
184	        await fs.remove(path.join(targetDir, entry));
185	      }
186	    }
187	  } catch {
188	    /* non-critical */
189	  }
190	}
191	
192	/**
193	 * Remove all SKF skills from all known IDE directories.
194	 * Used during uninstall.
195	 */
196	async function removeAllSkfSkills(projectDir) {
197	  const config = loadPlatforms();
198	  const removed = [];
199	
200	  for (const [, platform] of Object.entries(config.platforms)) {
201	    if (!platform.installer?.target_dir) continue;
202	    const targetDir = path.join(projectDir, platform.installer.target_dir);
203	    if (await fs.pathExists(targetDir)) {
204	      await cleanSkfSkills(targetDir);
205	      // Also clean legacy targets
206	      await cleanLegacyTargets(projectDir, platform);
207	      removed.push(platform.installer.target_dir);
208	    }
209	  }
210	
211	  return removed;
212	}
213	
214	module.exports = { installSkillsToIdes, getAvailablePlatforms, getDetectionMarkers, removeAllSkfSkills, loadPlatforms };
